    return true;

  }

  return false;

}

function() {
  var eligibleSubBenefitsValue = {{dlv - mybheligibleSubBenefits}}; 

  // Check if the value is undefined, null, or an empty string

  if (eligibleSubBenefitsValue === undefined || eligibleSubBenefitsValue === null || eligibleSubBenefitsValue === "") {
    return 'not-available';
  } else {
    return eligibleSubBenefitsValue;
  }
}

