        + ':' + pad(tzo % 60);
}

function() {
  // Get the page URL
  var pageUrl = {{Page URL}};

  // Retrieve the 'append' value from the data layer
  var appendValue = {{DLV - append}};

  if (appendValue) {
    // Parse the URL to separate the path and the query parameters/fragments
    var urlParts = pageUrl.split(/(\?|#)/);
    var baseUrl = urlParts[0];
    var queryAndFragment = urlParts.slice(1).join('');

    // Append the 'append' value to the base URL
    var modifiedUrl = baseUrl + appendValue + (queryAndFragment ? queryAndFragment : '');

    return modifiedUrl;
  } else {
    // Return the original URL if 'append' is null or not present
    return pageUrl;
  }
}

